import './index.css';
import React, { useState } from 'react';
import Header from "./components/Header";
import Sidebar from './components/Sidebar';
import TelaPeriodos from "./components/TelaPeriodos";
import TelaAlunos from "./components/TelaAlunos";
import TelaPacientes from "./components/TelaPacientes";
import TelaDisciplinas from "./components/TelaDisciplinas";
import TelaAgendamentos from "./components/TelaAgendamentos";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import Login from "./Login";
import DashboardAluno from "./DashboardAluno";
import DashboardRecepcao from "./DashboardRecepcao";
import DashboardDisciplinas from './DashboardDisciplinas';
import BottomNavBar from './components/BottomNavBar';
import { AuthProvider, useAuth } from './context/AuthContext';
import ProtectedRoute from './components/ProtectedRoute'; // Importe sua ProtectedRoute

// Layout principal: Header, Sidebar e conteúdo
function LayoutInterno() {
  const { user } = useAuth(); // Pega o user do contexto

  // Ajusta os menus para cada role:
  const [active, setActive] = useState('dashboard');

  function renderConteudo() {
    switch (active) {
      case 'dashboard':
        return user.role === 'recepcao' ? <DashboardRecepcao /> : <DashboardAluno />;
      case 'agendar':
        return <TelaAgendamentos />;
      case 'disciplinas':
        return <TelaDisciplinas />;
      case 'pacientes':
        return user.role === 'recepcao' ? <TelaPacientes /> : null;
      case 'alunos':
        return user.role === 'recepcao' ? <TelaAlunos /> : null;
      case 'periodos':
        return user.role === 'recepcao' ? <TelaPeriodos /> : null;
      default:
        return (
          <div>
            <h1 className="text-3xl font-bold mb-6">Página não encontrada</h1>
          </div>
        );
    }
  }

  return (
    <div className="bg-[#ffffff] min-h-screen">
      <Header />
      <div className="flex">
        {/* Sidebar só aparece em telas md+ (desktop/tablet) */}
        <div className="hidden md:block">
          <Sidebar active={active} onMenuClick={setActive} />
        </div>
        <main className="flex-1 ml-0 md:ml-64 mt-16 p-8 h-[calc(100vh-64px)] overflow-y-auto">
          <div className="mx-auto">{renderConteudo()}</div>
        </main>
      </div>
      {/* Bottom Navigation: só no mobile */}
      <BottomNavBar active={active} onMenuClick={setActive} />
    </div>
  );
}

// App principal
export default function App() {
  return (
    <AuthProvider>
      <Router>
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route
            path="/*"
            element={
              <ProtectedRoute>
                <LayoutInterno />
              </ProtectedRoute>
            }
          />
          {/* Se tentar acessar qualquer rota não mapeada, volta pro login */}
          <Route path="*" element={<Navigate to="/login" />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}
